        const parsed = parseInt(thresholdValue, 10);
        if (!isNaN(parsed)) threshold = parsed;
      }
      return { threshold };
    }
    return { threshold: 0 };
  } catch (error) {
    console.error("Error fetching free delivery settings:", error);
    return { threshold: 0 };
  }
}

