        inside: typeof data.inside === 'number' ? data.inside : defaults.inside,
        outside: typeof data.outside === 'number' ? data.outside : defaults.outside
      };
    }
    return defaults;
  } catch (error) {
    console.error("Error fetching delivery charges:", error);
    return defaults;
  }
